const payload = $json.body || {};
const data = payload.data || {};
const sessionId = payload.sessionId || '';
const msgType = (data.type || 'chat').toLowerCase();
const from = data.from || '';
const phoneNumber = from.replace('@c.us', '');
const body = data.body || '';
const fileName = data.fileName || null;
const caption = data.caption || '';
const lat = data.lat || null;
const lng = data.lng || null;

// تحويل نوع الرسالة إلى نص يفهمه الذكاء الاصطناعي
let aiPrompt = body;
if (msgType === 'image') {
  aiPrompt = `[ملاحظة من النظام: المستخدم أرسل صورة. الوصف المرفق معها: ${caption || 'لا يوجد وصف'}]`;
} else if (msgType === 'video') {
  aiPrompt = `[ملاحظة من النظام: المستخدم أرسل مقطع فيديو. الوصف المرفق معه: ${caption || 'لا يوجد وصف'}]`;
} else if (msgType === 'audio' || msgType === 'ptt') {
  aiPrompt = `[ملاحظة من النظام: المستخدم أرسل رسالة صوتية/مقطع صوتي]`;
} else if (msgType === 'document') {
  aiPrompt = `[ملاحظة من النظام: المستخدم أرسل ملف. اسم الملف: ${fileName || 'غير معروف'}]`;
} else if (msgType === 'location') {
  aiPrompt = `[ملاحظة من النظام: المستخدم أرسل موقع جغرافي. الإحداثيات: ${lat}, ${lng}]`;
} else if (msgType === 'sticker') {
  aiPrompt = `[ملاحظة من النظام: المستخدم أرسل ملصق (Sticker)]`;
} else if (msgType === 'vcard') {
  aiPrompt = `[ملاحظة من النظام: المستخدم أرسل بطاقة اتصال (vCard)]`;
}

return {
  sessionId,
  phoneNumber,
  aiPrompt,
  rawType: msgType
};

const originalData = $('🔍 Extract Message Fields').item.json;
const aiResponse = $json.output || 'عذراً، لم أتمكن من معالجة طلبك حالياً.';

return {
  sessionId: originalData.sessionId,
  phoneNumber: originalData.phoneNumber,
  replyText: aiResponse
};

const err = $json || {};
const status = err.statusCode || err.status || 'unknown';
const body = JSON.stringify(err.body || err.message || err);
console.error(`[WhatsApp Bot] Send failed — HTTP ${status}: ${body}`);
return { error: true, status, body };
